      "description": "Create a new job and enqueue it",
      "request_body": {
        "type": "string (required) — job category, e.g. email, report, image_resize",
        "payload": "string (optional) — arbitrary data passed to the worker",
        "priority": "integer (optional, default 0) — higher values are processed first"
      },
