        "201": "Job object with status='pending'",
        "400": "{ \"error\": \"...\" } — missing or invalid fields"
      }
    },
    {
      "method": "GET",
      "path": "/jobs",
      "description": "List all jobs, optionally filtered by status",
      "query_params": {
        "status": "pending | running | completed | failed | cancelled (optional)"
      },
      "responses": {
        "200": "Array of Job objects"
      }
    },
    {
      "method": "GET",
      "path": "/jobs/{id}",
      "description": "Get a single job by ID",
      "responses": {
        "200": "Job object",
        "404": "{ \"error\": \"job not found\" }"
      }
    },
    {
      "method": "POST",
      "path": "/jobs/{id}/cancel",
      "description": "Cancel a pending job. Only jobs in 'pending' status can be cancelled.",
      "responses": {
        "200": "Updated Job object with status='cancelled'",
        "404": "{ \"error\": \"job not found\" }",
        "409": "{ \"error\": \"...\" } — job is not in a cancellable state"
      }
    },
    {
      "method": "POST",
      "path": "/jobs/{id}/complete",
      "description": "Mark a running job as completed (called by the worker after finishing)",
      "responses": {
        "200": "Updated Job object with status='completed'",
        "404": "{ \"error\": \"job not found\" }",
        "409": "{ \"error\": \"...\" } — job is not running"
      }
    },
    {
      "method": "POST",
      "path": "/jobs/{id}/fail",
      "description": "Mark a running job as failed (called by the worker on error)",
      "responses": {
        "200": "Updated Job object with status='failed'",
        "404": "{ \"error\": \"job not found\" }",
        "409": "{ \"error\": \"...\" } — job is not running"
      }
    },
    {
      "method": "POST",
      "path": "/workers/register",
      "description": "Register a new worker node",
      "request_body": {
        "name": "string (required) — unique worker name"
      },
      "responses": {
        "201": "Worker object",
        "400": "{ \"error\": \"...\" }"
      }
    },
    {
      "method": "GET",
      "path": "/workers",
      "description": "List all registered workers",
      "responses": {
        "200": "Array of Worker objects"
      }
    },
    {
      "method": "GET",
      "path": "/stats",
      "description": "Get queue depth by status",
      "responses": {
        "200": "{ \"pending\": N, \"running\": N, \"completed\": N, \"failed\": N, \"cancelled\": N }"
      }
    }
  ],
  "job_object": {
    "id": "integer",
    "type": "string",
    "payload": "string",
    "status": "pending | running | completed | failed | cancelled",
    "priority": "integer",
    "worker_id": "integer | null",
    "worker_name": "string (name of the assigned worker, empty if unassigned)",
    "created_at": "ISO8601 datetime",
    "updated_at": "ISO8601 datetime"
  },
  "worker_object": {
    "id": "integer",
    "name": "string",
    "status": "idle | busy",
    "registered_at": "ISO8601 datetime"
  }
}
